  "verses": [
    {
      "n": 17,
      "column": "left",
      "text": "Un tas KUNGS runna-\nja us Mohsu/un fazzija:\n"
    },
    {
      "n": 18,
      "column": "left",
      "text": "Tew buhs arridsan wee-\nnu Masgaſchanas Trauku no\nWarra taiſht/ un winna Kahju\narridsan no Warra par Masga-\nfchami/ un tew buhs to ſtarp to\nSa-eefchanas Telti likt/ un ſtarp\nto Altari/ un tur Uhdent eeſeet.\n"
    },
    {
      "n": 19,
      "column": "left",
      "text": "Ka Aarons un winna\nDehli is ta fawas Rohkas un\ntawas Kahjas warr masgaht.\n"
    },
    {
      "n": 20,
      "column": "left",
      "text": "Rad teem eekſch tahs Sa-\neefchanas Telts irr ja-eet / tad\nbuhs teem ar Uhdeni masgatees/\nka tee ne mirſt / jeb kad tee nahk\npee ta Altara kalpoht / un eede-\ndſinaht ta KUNGA Ugguni.\n"
    },
    {
      "n": 21,
      "column": "left",
      "text": "Tad buhs teem fawas\nRohkas/ un fawas Kahjas mas-\ngaht / ka tee ne mirſt / un tas\nbuhs teem weens Likkums/ wiz-\nxain un winna Dſunnumam\ninuhſcham/ pee winnu Pehznaḥ-\nkanteem.\n"
    },
    {
      "n": 22,
      "column": "left",
      "text": "Un tas KUNGS runna-\nja us Mohsu/ un fazzija:\n"
    },
    {
      "n": 23,
      "column": "left",
      "text": "Tu tad nemm pee ſewim\nDahrgas Sahles / itt ſchſihſtas\nMirres peeſſints Sihketus / un\nKaneles puſs tik dauds/ (proh-\nti) diwiſints un peeſdefinits\nSihketus/ ir Kalinuſa diwiſints\nun peeſdefinits Sihketus.\n"
    },
    {
      "n": 24,
      "column": "left",
      "text": "Ir Kaſijas peeſſints Sih-\nketus/ pehz tahs ſwehtas Weetas\nSihketā / un weenu Junu Efjes\nno Efjes-Rohkeim.\n"
    },
    {
      "n": 25,
      "column": "right",
      "text": "Un darri no ta t\ntas Swaidiſchanas-Efj\nSwaidannu Salwi pehz ?\nWiſt / ta buhs tah\nSwaidiſchanas-Efje.\n"
    },
    {
      "n": 26,
      "column": "right",
      "text": "Un ſwaidi ar to\neeschanas Telti/un tahs\nSchkirſtu/\n"
    },
    {
      "n": 27,
      "column": "right",
      "text": "To Gaſdu ar wiſ\nna Rihkeim / un to\nwinna Rihkeim/un to\nAltari.\n"
    },
    {
      "n": 28,
      "column": "right",
      "text": "Un to Dedſama-\nAltari ar wiſſeim wiſ\nkeim/un to Masgaſchan-\nfu ar winna Kahju.\n"
    },
    {
      "n": 29,
      "column": "right",
      "text": "Tew buhs tohs\ntiht / ka tee to ſive\nSwehtiba effus/ iffatu\ntohs aiskarr/ tas taps\n"
    },
    {
      "n": 30,
      "column": "right",
      "text": "Tew buhs arrids\nnu un winna Dehſus\nun tew buhs tohs eefwe\ntee manni Preesteri effi\n"
    },
    {
      "n": 31,
      "column": "right",
      "text": "Un tew buhs u\nBehrneim runnaht / un\nSchibuhs ta ſwehta Sw\nnas-Etje preeſſch mann,\nfeem Pehznaḥkanteem.\n"
    },
    {
      "n": 32,
      "column": "right",
      "text": "To ne buhs us\nZilweka Meeſu ſeet/ jun\nbuhs tahdn taiſht/ kas\nirr / ta irr ſwehta / un\njums ſwehtai buht.\n"
    },
    {
      "n": 33,
      "column": "right",
      "text": "Kursch tahdn p\nlas tai lihſa irr / un\ntahs us kahdu Sweſchu\nbuhs iſdeldeſain tapt n\nLaudim.\n"
    },
    {
      "n": 34,
      "column": "right",
      "text": "Wehl fazzija ta\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
